import React, { useEffect, useState } from 'react';
import axios from 'axios';

const Home = () => {
  const [media, setMedia] = useState([]);

  useEffect(() => {
    async function fetch() {
      const res = await axios.get(`${process.env.REACT_APP_API_URL}/media`);
      setMedia(res.data);
    }
    fetch();
  }, []);

  return (
    <div style={{ padding: '1rem' }}>
      <h1>Home Feed</h1>
      {media.map((m) => (
        <div key={m._id}>
          <h3>{m.title}</h3>
          <p>by {m.uploader?.username}</p>
        </div>
      ))}
    </div>
  );
};

export default Home;
